Here's how to test `DataFetcher` with MSTest 3.x+, covering success, failure, timeout, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler("hello world", HttpStatusCode.OK);
        var sut = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await sut.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_ErrorResponse_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler("", HttpStatusCode.InternalServerError);
        var sut = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await sut.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(5000)] // enforces a 5-second ceiling
    public async Task FetchAsync_WithTimeout_CompletesInTime()
    {
        var handler = new FakeHandler("fast", HttpStatusCode.OK);
        var sut = new DataFetcher(new HttpClient(handler));

        // Pass TestContext.CancellationToken so the [Timeout]
        // can cancel the test cooperatively
        var result = await sut.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }

    [TestMethod]
    public async Task FetchAsync_WhenCancelled_ThrowsTaskCanceledException()
    {
        var handler = new DelayHandler(TimeSpan.FromSeconds(30));
        var sut = new DataFetcher(new HttpClient(handler));

        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await sut.FetchAsync("https://example.com", cts.Token));
    }

    // --- Test helpers ---

    private sealed class FakeHandler(string content, HttpStatusCode status)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(new HttpResponseMessage(status)
            {
                Content = new StringContent(content),
            });
        }
    }

    private sealed class DelayHandler(TimeSpan delay) : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            await Task.Delay(delay, cancellationToken);
            return new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key patterns used:**

| Technique | Why |
|---|---|
| `TestContext` via constructor | Enables `readonly`, satisfies nullability |
| `[Timeout] + _testContext.CancellationToken` | Cooperative timeout — MSTest cancels the token when time expires |
| `Assert.ThrowsExactlyAsync<T>` | Replaces `[ExpectedException]`, lets you inspect the exception |
| Custom `HttpMessageHandler` | Avoids mocking frameworks; gives full control over HTTP behavior |
| `sealed` test class | MSTest best practice for performance |

The critical insight: `[Timeout]` alone doesn't kill a stuck async call — you **must** pass `TestContext.CancellationToken` into the method under test so the timeout can propagate cooperatively.
